import java.util.Scanner;
import java.nio.charset.StandardCharsets;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure that the length of user input does not exceed the buffer size
        byte[] buffer = new byte[10];
        int length = Math.min(name.length(), buffer.length);

        // Copy only up to 'length' bytes from the input into the buffer
        System.arraycopy(name.getBytes(StandardCharsets.UTF_8), 0, buffer, 0, length);

        System.out.println("Hello, " + new String(buffer, StandardCharsets.UTF_8).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
